DANGER_PATTERNS = [
    r'rm\s+-rf',
    r'del\s+/f\s+/q',
    r'exec\(',
    r'eval\(',
    r'\b(open|file|socket)\(',
    r'curl\s+[^\s]+\.exe',
    r'wget\s+[^\s]+\.sh'
]

def scan_code_safety(code):
    for pattern in DANGER_PATTERNS:
        if re.search(pattern, code, re.IGNORECASE):
            return {'safe': False, 'pattern': pattern}
    return {'safe': True}

def ag2_code_hook(code_message):
    result = scan_code_safety(code_message.content)
    if not result['safe']:
        VexMonitor.flag('MALICIOUS_CODE', details={'pattern': result['pattern']})
        return {'type': 'text', 'content': 'Code execution blocked: dangerous pattern detected'}
    return code_message

# Register with AG2 CodeExecutorAgent
code_agent.register_hook(ag2_code_hook)

