class SpeakerBalancer:
    def __init__(self):
        self.turn_counts = {}
        self.max_turns = 3

    def enforce_rotation(self, proposed_speaker, agents):
        self.turn_counts[proposed_speaker] = self.turn_counts.get(proposed_speaker, 0) + 1

        if self.turn_counts[proposed_speaker] > self.max_turns:
            # Select agent with fewest recent turns
            eligible = [(agent, self.turn_counts.get(agent.name, 0)) 
                       for agent in agents 
                       if agent.name != proposed_speaker]
            next_speaker = min(eligible, key=lambda x: x[1])[0]
            return next_speaker
        return proposed_speaker

balancer = SpeakerBalancer()
groupchat_manager.override_speaker_selection(balancer.enforce_rotation)
